1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	const COMPONENT_INSURANCE_VALUE = 250;
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_YEARS_THRESHOLD = 2;
12	const FOLLOWUP_DISCOUNT_RATE = 0.15;
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
16	const HALF_PAYOUT_RATE = 0.5;
17	
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	};
24	
25	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	};
31	
32	type Item = {
33	  type: string;
34	  material?: string;
35	  enchantment?: number;
36	  cursed?: boolean;
37	};
38	type Damage = { itemType: string; amount: number };
39	type Incident = { cause: string; damages: Damage[] };
40	type QuoteStep = { op: "quote"; items: Item[] };
41	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
42	type Step = QuoteStep | ClaimStep;
43	type Customer = { yearsWithMHPCO: number; firstQuote?: boolean };
44	type Scenario = { customer: Customer; steps: Step[] };
45	
46	const componentGroupPremium = (count: number): number =>
47	  count === COMPONENT_BLOCK_SIZE
48	    ? COMPONENT_BLOCK_PREMIUM
49	    : count * COMPONENT_BASE_PREMIUM;
50	
51	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
52	
53	const isHighEnchantment = (item: Item): boolean =>
54	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
55	
56	const qualifiesForFirstInsurance = (item: Item, isSingleItemPolicy: boolean): boolean =>
57	  isSingleItemPolicy && !!item.cursed && !isHighEnchantment(item);
58	
59	const surchargeRates = (item: Item, isSingleItemPolicy: boolean): number[] => [
60	  item.cursed ? CURSE_SURCHARGE_RATE : 0,
61	  isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0,
62	  qualifiesForFirstInsurance(item, isSingleItemPolicy) ? FIRST_INSURANCE_RATE : 0,
63	];
64	
65	const mainItemPremium = (item: Item, isSingleItemPolicy: boolean): number => {
66	  const base = BASE_PREMIUM_BY_TYPE[item.type];
67	  const totalRate = surchargeRates(item, isSingleItemPolicy).reduce((a, b) => a + b, 1);
68	  return base * totalRate;
69	};
70	
71	const countByType = (items: Item[]): Map<string, number> =>
72	  items.reduce(
73	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
74	    new Map<string, number>(),
75	  );
76	
77	const sumComponentPremiums = (components: Item[]): number =>
78	  [...countByType(components).values()]
79	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
80	
81	const partitionItems = (items: Item[]): { mains: Item[]; components: Item[] } =>
82	  items.reduce<{ mains: Item[]; components: Item[] }>(
83	    (acc, item) => {
84	      (isMainItem(item) ? acc.mains : acc.components).push(item);
85	      return acc;
86	    },
87	    { mains: [], components: [] },
88	  );
89	
90	const sumItemPremiums = (items: Item[], policyRate: number): number => {
91	  const { mains, components } = partitionItems(items);
92	  const isSingleItemPolicy = items.length === 1;
93	  const mainsBaseSum = mains.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
94	  const mainsPremiumSum = mains.reduce((sum, item) => sum + mainItemPremium(item, isSingleItemPolicy), 0);
95	  const componentsSum = sumComponentPremiums(components);
96	  return mainsPremiumSum + componentsSum + (mainsBaseSum + componentsSum) * policyRate;
97	};
98	
99	const customerRateAdjustments = (customer: Customer, isFollowUp: boolean): number[] => [
100	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -LOYALTY_DISCOUNT_RATE : 0,
101	  customer.firstQuote ? FIRST_INSURANCE_RATE : 0,
102	  isFollowUp ? -FOLLOWUP_DISCOUNT_RATE : 0,
103	];
104	
105	const policyWideRate = (customer: Customer, isFollowUp: boolean): number =>
106	  customerRateAdjustments(customer, isFollowUp).reduce((sum, rate) => sum + rate, 0);
107	
108	const ceilInFavor = (value: number): number => Math.ceil(Number(value.toFixed(6)));
109	
110	const quotePremiumFor = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => ({
111	  premium: ceilInFavor(sumItemPremiums(step.items, policyWideRate(customer, isFollowUp)) + PROCESSING_FEE),
112	});
113	
114	const itemInsuranceValue = (item: Item): number =>
115	  isMainItem(item) ? INSURANCE_VALUE_BY_TYPE[item.type] : COMPONENT_INSURANCE_VALUE;
116	
117	const policyInsuranceSum = (items: Item[]): number =>
118	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
119	
120	const reimbursementRate = (item: Item | undefined): number =>
121	  item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD ? HALF_PAYOUT_RATE : 1;
122	
123	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
124	  const item = policyItems.find((i) => i.type === damage.itemType);
125	  const reimbursed = damage.amount * reimbursementRate(item);
126	  return Math.max(0, reimbursed - DEDUCTIBLE);
127	};
128	
129	const claimResult = (step: ClaimStep, policyItems: Item[]): { payout: number; remainingCap: number } => {
130	  const insuranceSum = policyInsuranceSum(policyItems);
131	  const cap = insuranceSum * CAP_MULTIPLIER;
132	  const payout = step.incident.damages.reduce((sum, d) => sum + damagePayout(d, policyItems), 0);
133	  return { payout, remainingCap: cap - payout };
134	};
135	
136	const runStep = (step: Step, index: number, scenario: Scenario): unknown =>
137	  step.op === "quote"
138	    ? quotePremiumFor(step, scenario.customer, index > 0)
139	    : claimResult(step, (scenario.steps[step.policy] as QuoteStep).items);
140	
141	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
142	  results: scenario.steps.map((step, i) => runStep(step, i, scenario)),
143	});
